def emit_section_header(file):
  header = """\
// {{$nv-internal-release begin}}
////////////////////////////////////////////////////////////////////////////////////////////////////
//
// BEGIN GENERATED SECTION
//
// This section was generated by tools/generators/scripts/{script} with the following
// usage:
//
//   $ cd tools/generators/scripts
//   $ python3 {cmd}
//
// DO NOT EDIT!
//
////////////////////////////////////////////////////////////////////////////////////////////////////
// {{$nv-internal-release end}}

""".format(script=osp.basename(sys.argv[0]), cmd=' '.join(sys.argv))
  file.write(header)

def emit_section_footer(file):
  footer = """\
// {$nv-internal-release begin}
////////////////////////////////////////////////////////////////////////////////////////////////////
//
// END GENERATED SECTION
//
////////////////////////////////////////////////////////////////////////////////////////////////////
// {$nv-internal-release end}

"""
  file.write(footer)

def emit_namespace_header(file, namespace):
  header = """\
////////////////////////////////////////////////////////////////////////////////////////////////////

namespace{_namespace} {{

////////////////////////////////////////////////////////////////////////////////////////////////////

""".format(_namespace = ' ' + namespace if namespace != '' else '')
  file.write(header)

def emit_namespace_footer(file, namespace):
  footer = """\
////////////////////////////////////////////////////////////////////////////////////////////////////

}} // namespace{_namespace}

////////////////////////////////////////////////////////////////////////////////////////////////////

""".format(_namespace = ' ' + namespace if namespace != '' else '')
  file.write(footer)


def post_separator(function):
  def wrapped(outfile, *args, **kwargs):
    function(outfile, *args, **kwargs)
    outfile.write("""\

////////////////////////////////////////////////////////////////////////////////////////////////////

""")
  return wrapped


