class MmaOperandSource(enum.Enum):
  reg = enum_auto()
  smem_desc = enum_auto()


class MmaKind(enum.Enum):
  dense = enum_auto()
  sparse = enum_auto()


class MmaAtomConfig:
  def __init__(
          self,
          mma_tag: str,
          m: int,
          n: int,
          k: int,
          atype: DataType,
          asource: MmaOperandSource,
          btype: DataType,
          bsource: MmaOperandSource,
          cdtype: DataType,
          csource: MmaOperandSource,
          threads: int,
          transA: bool,
          transB: bool,
          min_toolkit: int,
          sm_arch: int,
          modifier: MmaPtxModifier = MmaPtxModifier.kNone,
          blockscale_vecsize: list = [0],
          sftype: DataType = DataType.ue8m0,
          sfsource: MmaOperandSource = MmaOperandSource.reg,
          kind: MmaKind = MmaKind.dense
          ):
    self.tag = mma_tag
    self.m = m
    self.n = n
    self.k = k
    self.threads = threads
    self.transA = transA  # false if col-major, true if row-major
    self.transB = transB  # false if col-major, true if row-major
    self.atype = atype
    self.asource = asource
    self.btype = btype
    self.bsource = bsource
    self.cdtype = cdtype
    self.csource = csource
    self.sftype = sftype
    self.sfsource = sfsource
    self.min_toolkit = min_toolkit
    self.max_toolkit = 4096
    self.sm_arch = sm_arch
    self.modifier = modifier
    self.blockscale_vecsize = blockscale_vecsize
    self.kind = kind
